{"filter":false,"title":"ejercicio2semana4.py","tooltip":"/taller-2706-11/semana4/ejercicio2semana4.py","undoManager":{"mark":0,"position":0,"stack":[[{"start":{"row":0,"column":0},"end":{"row":39,"column":0},"action":"insert","lines":["# Datos de prueba","vendedores = [\"Hugo\", \"Mariana\", \"Luis\", \"Jennifer\", \"Jorge\", \"Valeria\", \"Manuel\"]","ventas = [15, 16, 1, 0, 4, 15, 13]","","# 1. Total de unidades vendidas","def obtener_total_vendido(arreglo_ventas):","    total = 0","    for v in arreglo_ventas:","        total += v","    return total","","# 2. Porcentaje de vendedores que superaron la cuota (> 5)","def porcentaje_superaron_cuota(arreglo_ventas):","    cantidad_superaron = 0","    for v in arreglo_ventas:","        if v > 5:","            cantidad_superaron += 1","    porcentaje = (cantidad_superaron / len(arreglo_ventas)) * 100","    return porcentaje","","# 3. Agentes de ventas que superaron la cuota","def agentes_superaron_cuota(arreglo_vendedores, arreglo_ventas):","    superaron = []","    for i in range(len(arreglo_ventas)):","        if arreglo_ventas[i] > 5:","            superaron.append(arreglo_vendedores[i])","    return superaron","","# 4. Total a pagar por comisión (300 soles por unidad)","def calcular_comisiones(arreglo_ventas):","    total_unidades = obtener_total_vendido(arreglo_ventas)","    return total_unidades * 300","","# --- EJECUCIÓN DE PRUEBA ---","print(\"--- RESULTADOS PREGUNTA 1 ---\")","print(f\"Total unidades vendidas: {obtener_total_vendido(ventas)}\")","print(f\"Porcentaje que superó la cuota: {porcentaje_superaron_cuota(ventas):.2f}%\")","print(f\"Vendedores que superaron la cuota: {agentes_superaron_cuota(vendedores, ventas)}\")","print(f\"Total a pagar en comisiones: S/. {calcular_comisiones(ventas)}\")",""],"id":1}]]},"ace":{"folds":[],"scrolltop":0,"scrollleft":0,"selection":{"start":{"row":39,"column":0},"end":{"row":39,"column":0},"isBackwards":false},"options":{"guessTabSize":true,"useWrapMode":false,"wrapToView":true},"firstLineState":0},"timestamp":1782874429507,"hash":"df8a6b0d9f8ce825269df715dd70ab65afd5403b"}